"""Pneumonia Detection — Streamlit Inference App=============================================Upload a chest X-ray → get a classification (Normal / Pneumonia),confidence score, and Grad-CAM heatmap overlay.Usage:    streamlit run app.pyRequires:    - checkpoints/pneumonia_resnet50.pth   (model weights from training notebook)    - torch, torchvision, streamlit, pillow, numpy, matplotlib, scipy"""import ioimport osimport timeimport matplotlib.pyplot as pltimport matplotlib.cm as cmimport numpy as npimport streamlit as stimport torchimport torch.nn as nnimport torchvision.models as modelsimport torchvision.transforms as Tfrom PIL import Imagefrom scipy.ndimage import zoomfrom scipy.special import expit as sigmoid# ─── Page config ──────────────────────────────────────────────────────────────st.set_page_config(    page_title="PneumoScan AI",    page_icon="🫁",    layout="wide",    initial_sidebar_state="expanded",)# ─── Custom CSS ───────────────────────────────────────────────────────────────st.markdown("""<style>/* Import medical-grade fonts */@import url('https://fonts.googleapis.com/css2?family=IBM+Plex+Mono:wght@400;500&family=IBM+Plex+Sans:wght@300;400;500;600&display=swap');html, body, [class*="css"] {    font-family: 'IBM Plex Sans', sans-serif;}/* Dark clinical theme */.stApp {    background-color: #0a0e14;    color: #c8d3e0;}/* Header strip */.app-header {    background: linear-gradient(135deg, #0f1923 0%, #12263a 100%);    border-bottom: 1px solid #1e3a5f;    padding: 1.4rem 2rem;    margin-bottom: 1.5rem;    border-radius: 0 0 12px 12px;}.app-header h1 {    font-family: 'IBM Plex Mono', monospace;    font-size: 1.6rem;    font-weight: 500;    color: #7ecfff;    letter-spacing: 0.04em;    margin: 0;}.app-header p {    color: #5a7fa0;    font-size: 0.82rem;    margin: 0.3rem 0 0;    font-weight: 300;}/* Result cards */.result-card {    background: #0f1923;    border: 1px solid #1e3a5f;    border-radius: 12px;    padding: 1.4rem 1.6rem;    margin-bottom: 1rem;}.result-card h3 {    font-family: 'IBM Plex Mono', monospace;    font-size: 0.75rem;    font-weight: 500;    color: #5a7fa0;    letter-spacing: 0.12em;    text-transform: uppercase;    margin: 0 0 0.5rem;}/* Prediction badge */.badge-pneumonia {    display: inline-block;    background: #3d0f0f;    border: 1px solid #c0392b;    color: #ff6b6b;    font-family: 'IBM Plex Mono', monospace;    font-size: 1.1rem;    font-weight: 500;    padding: 0.45rem 1.1rem;    border-radius: 6px;    letter-spacing: 0.08em;}.badge-normal {    display: inline-block;    background: #0d2d1a;    border: 1px solid #27ae60;    color: #55d68d;    font-family: 'IBM Plex Mono', monospace;    font-size: 1.1rem;    font-weight: 500;    padding: 0.45rem 1.1rem;    border-radius: 6px;    letter-spacing: 0.08em;}/* Confidence bar */.conf-bar-container {    background: #1a2535;    border-radius: 4px;    height: 8px;    overflow: hidden;    margin-top: 0.5rem;}.conf-bar-fill-pneumonia {    background: linear-gradient(90deg, #c0392b, #e74c3c);    height: 100%;    border-radius: 4px;    transition: width 0.8s ease;}.conf-bar-fill-normal {    background: linear-gradient(90deg, #1e8449, #27ae60);    height: 100%;    border-radius: 4px;    transition: width 0.8s ease;}/* Metric tiles */.metric-tile {    background: #0f1923;    border: 1px solid #1e3a5f;    border-radius: 10px;    padding: 1rem 1.2rem;    text-align: center;}.metric-tile .value {    font-family: 'IBM Plex Mono', monospace;    font-size: 1.6rem;    font-weight: 500;    color: #7ecfff;    line-height: 1;}.metric-tile .label {    font-size: 0.72rem;    font-weight: 400;    color: #5a7fa0;    text-transform: uppercase;    letter-spacing: 0.1em;    margin-top: 0.4rem;}/* Sidebar */[data-testid="stSidebar"] {    background-color: #0c1420;    border-right: 1px solid #1e3a5f;}[data-testid="stSidebar"] * {    color: #8aa8c2 !important;}[data-testid="stSidebar"] h2, [data-testid="stSidebar"] h3 {    color: #7ecfff !important;    font-family: 'IBM Plex Mono', monospace !important;    font-size: 0.8rem !important;    letter-spacing: 0.1em !important;    text-transform: uppercase !important;}/* File uploader */[data-testid="stFileUploader"] {    background: #0f1923;    border: 1px dashed #2a4a6b;    border-radius: 10px;    padding: 0.5rem;}/* Tabs */.stTabs [data-baseweb="tab-list"] {    background: #0c1420;    border-bottom: 1px solid #1e3a5f;    gap: 0;}.stTabs [data-baseweb="tab"] {    font-family: 'IBM Plex Mono', monospace;    font-size: 0.78rem;    letter-spacing: 0.08em;    color: #5a7fa0;    padding: 0.6rem 1.4rem;}.stTabs [aria-selected="true"] {    color: #7ecfff;    border-bottom: 2px solid #7ecfff;}/* Disclaimer */.disclaimer {    background: #1a1200;    border: 1px solid #4d3800;    border-left: 3px solid #f39c12;    border-radius: 8px;    padding: 0.9rem 1.1rem;    font-size: 0.8rem;    color: #b8a060;    margin-top: 1rem;}/* Hide streamlit menu/footer */#MainMenu, footer { visibility: hidden; }header { visibility: hidden; }</style>""", unsafe_allow_html=True)# ─── Constants ────────────────────────────────────────────────────────────────IMG_SIZE       = 224CHECKPOINT     = "./checkpoints/pneumonia_resnet50.pth"IMAGENET_MEAN  = [0.485, 0.456, 0.406]IMAGENET_STD   = [0.229, 0.224, 0.225]DEVICE         = torch.device("cuda" if torch.cuda.is_available() else "cpu")# ─── Model definition (must match training notebook exactly) ──────────────────@st.cache_resourcedef load_model():    model = models.resnet50(weights=None)    in_features = model.fc.in_features          # 2048    model.fc = nn.Sequential(        nn.Linear(in_features, 256),        nn.ReLU(inplace=True),        nn.Dropout(0.4),        nn.Linear(256, 1),    )    if os.path.exists(CHECKPOINT):        state = torch.load(CHECKPOINT, map_location=DEVICE)        model.load_state_dict(state)        model_loaded = True    else:        model_loaded = False    model.eval()    model.to(DEVICE)    return model, model_loaded# ─── Transforms ───────────────────────────────────────────────────────────────eval_transform = T.Compose([    T.Grayscale(num_output_channels=3),    T.Resize((IMG_SIZE, IMG_SIZE)),    T.ToTensor(),    T.Normalize(mean=IMAGENET_MEAN, std=IMAGENET_STD),])# ─── Grad-CAM ────────────────────────────────────────────────────────────────class GradCAM:    def __init__(self, model, target_layer):        self.model        = model        self.target_layer = target_layer        self.activations  = None        self.gradients    = None        self._register_hooks()    def _register_hooks(self):        def fwd_hook(module, inp, out):            self.activations = out.detach()        def bwd_hook(module, grad_in, grad_out):            self.gradients = grad_out[0].detach()        self.target_layer.register_forward_hook(fwd_hook)        self.target_layer.register_full_backward_hook(bwd_hook)    def __call__(self, x):        self.model.eval()        x = x.requires_grad_(True)        logit = self.model(x)        self.model.zero_grad()        logit[0, 0].backward()        alphas = self.gradients.mean(dim=(2, 3), keepdim=True)        cam = (alphas * self.activations).sum(dim=1, keepdim=True)        cam = torch.relu(cam).squeeze().cpu().numpy()        scale = x.shape[-1] / cam.shape[-1]        cam   = zoom(cam, scale, order=1)        cam   = (cam - cam.min()) / (cam.max() - cam.min() + 1e-8)        return cam# ─── Inference helper ─────────────────────────────────────────────────────────def run_inference(pil_image, model):    tensor = eval_transform(pil_image).unsqueeze(0).to(DEVICE)    # Prediction    with torch.no_grad():        logit = model(tensor).item()    prob_pneumonia = float(sigmoid(logit))    prob_normal    = 1.0 - prob_pneumonia    label          = "Pneumonia" if prob_pneumonia >= 0.5 else "Normal"    confidence     = prob_pneumonia if label == "Pneumonia" else prob_normal    # Grad-CAM    gcam      = GradCAM(model, target_layer=model.layer4[-1])    tensor_gc = eval_transform(pil_image).unsqueeze(0).to(DEVICE)    heatmap   = gcam(tensor_gc)    return {        "label":           label,        "confidence":      confidence,        "prob_pneumonia":  prob_pneumonia,        "prob_normal":     prob_normal,        "logit":           logit,        "heatmap":         heatmap,    }def make_overlay(pil_image, heatmap, alpha=0.45, colormap="jet"):    """Return PIL image of original X-ray with Grad-CAM overlay."""    orig = np.array(pil_image.convert("L").resize((IMG_SIZE, IMG_SIZE)))    orig_rgb = np.stack([orig, orig, orig], axis=-1)    cmap  = cm.get_cmap(colormap)    heat_rgb = (cmap(heatmap)[:, :, :3] * 255).astype(np.uint8)    overlay = (alpha * heat_rgb + (1 - alpha) * orig_rgb).astype(np.uint8)    return Image.fromarray(overlay)def make_bar_chart(prob_normal, prob_pneumonia):    """Return a matplotlib figure with a horizontal bar chart of probabilities."""    fig, ax = plt.subplots(figsize=(5, 1.6))    fig.patch.set_facecolor("#0f1923")    ax.set_facecolor("#0f1923")    categories = ["Normal", "Pneumonia"]    values     = [prob_normal * 100, prob_pneumonia * 100]    colors     = ["#27ae60", "#e74c3c"]    bars = ax.barh(categories, values, color=colors, height=0.45, edgecolor="none")    for bar, val in zip(bars, values):        ax.text(val + 1.5, bar.get_y() + bar.get_height() / 2,                f"{val:.1f}%", va="center", color="#c8d3e0",                fontsize=9, fontfamily="monospace")    ax.set_xlim(0, 115)    ax.set_xlabel("Probability (%)", color="#5a7fa0", fontsize=8)    ax.tick_params(colors="#8aa8c2", labelsize=9)    ax.spines[["top", "right", "bottom"]].set_visible(False)    ax.spines["left"].set_color("#1e3a5f")    ax.set_facecolor("#0f1923")    for spine in ax.spines.values():        spine.set_color("#1e3a5f")    plt.tight_layout(pad=0.5)    return figdef make_heatmap_distribution(heatmap):    """Return histogram of Grad-CAM activation values."""    fig, ax = plt.subplots(figsize=(5, 2))    fig.patch.set_facecolor("#0f1923")    ax.set_facecolor("#0f1923")    ax.hist(heatmap.ravel(), bins=50, color="#7ecfff", alpha=0.8, edgecolor="none")    ax.axvline(0.5, color="#f39c12", linestyle="--", linewidth=1, label="midpoint")    ax.set_xlabel("Activation intensity", color="#5a7fa0", fontsize=8)    ax.set_ylabel("Pixel count", color="#5a7fa0", fontsize=8)    ax.set_title("Grad-CAM activation distribution", color="#8aa8c2", fontsize=9, pad=6)    ax.tick_params(colors="#8aa8c2", labelsize=8)    for spine in ax.spines.values():        spine.set_color("#1e3a5f")    ax.legend(fontsize=7, labelcolor="#c8d3e0",              facecolor="#0f1923", edgecolor="#1e3a5f")    plt.tight_layout(pad=0.5)    return figdef make_region_activation(heatmap):    """Bar chart of mean Grad-CAM activation across 9 anatomical image regions (3×3 grid)."""    h, w  = heatmap.shape    rh, rw = h // 3, w // 3    region_labels = [        "Top-left",    "Top-center",    "Top-right",        "Mid-left",    "Mid-center",    "Mid-right",        "Bot-left",    "Bot-center",    "Bot-right",    ]    values = []    for row in range(3):        for col in range(3):            patch = heatmap[row*rh:(row+1)*rh, col*rw:(col+1)*rw]            values.append(patch.mean())    values = np.array(values)    # Color bars by intensity: low=blue, high=red    norm   = plt.Normalize(values.min(), values.max())    colors = plt.get_cmap("RdYlBu_r")(norm(values))    fig, ax = plt.subplots(figsize=(5, 2.8))    fig.patch.set_facecolor("#0f1923")    ax.set_facecolor("#0f1923")    bars = ax.barh(region_labels[::-1], values[::-1], color=colors[::-1],                   height=0.6, edgecolor="none")    for bar, val in zip(bars, values[::-1]):        ax.text(val + 0.005, bar.get_y() + bar.get_height() / 2,                f"{val:.3f}", va="center", color="#c8d3e0", fontsize=8,                fontfamily="monospace")    ax.set_xlim(0, values.max() * 1.25)    ax.set_xlabel("Mean activation", color="#5a7fa0", fontsize=8)    ax.set_title("Activation by image region", color="#8aa8c2", fontsize=9, pad=6)    ax.tick_params(colors="#8aa8c2", labelsize=8)    for spine in ax.spines.values():        spine.set_color("#1e3a5f")    ax.spines["top"].set_visible(False)    ax.spines["right"].set_visible(False)    plt.tight_layout(pad=0.5)    focus_pct = (heatmap >= 0.5).mean() * 100    return fig, focus_pctdef fig_to_pil(fig):    buf = io.BytesIO()    fig.savefig(buf, format="png", dpi=150, bbox_inches="tight",                facecolor=fig.get_facecolor())    buf.seek(0)    return Image.open(buf)# ─── Sidebar ─────────────────────────────────────────────────────────────────with st.sidebar:    st.markdown("## PneumoScan AI")    st.markdown("---")    st.markdown("### Model")    st.markdown(        "ResNet50 with two-phase transfer learning.  \n"        "Pre-trained on ImageNet, fine-tuned on 4,700+ CXR images."    )    st.markdown("### Grad-CAM layer")    st.markdown("`model.layer4[-1]`  \nLast residual block before GAP.")    st.markdown("---")    st.markdown("### Settings")    threshold   = st.slider("Decision threshold", 0.1, 0.9, 0.5, 0.01,                             help="Probability above which image is classified as Pneumonia.")    cam_alpha   = st.slider("Heatmap opacity", 0.1, 0.9, 0.45, 0.05)    colormap    = st.selectbox("Heatmap colormap", ["jet", "hot", "inferno", "YlOrRd"], index=0)    st.markdown("---")    st.markdown("### Device")    device_str = "🟢 GPU (CUDA)" if torch.cuda.is_available() else "🟡 CPU"    st.markdown(f"`{device_str}`")    if torch.cuda.is_available():        st.markdown(f"`{torch.cuda.get_device_name(0)}`")# ─── Header ──────────────────────────────────────────────────────────────────st.markdown("""<div class="app-header">  <h1>🫁 PneumoScan AI</h1>  <p>Explainable pneumonia detection from chest X-rays · ResNet50 + Grad-CAM · Beta v1.0</p></div>""", unsafe_allow_html=True)# ─── Load model ───────────────────────────────────────────────────────────────model, model_loaded = load_model()if not model_loaded:    st.warning(        "⚠️  Model weights not found at `./checkpoints/pneumonia_resnet50.pth`.  \n"        "Run the training notebook end-to-end first, then place the checkpoint in `checkpoints/`.  \n"        "The app will still run but predictions will be random (untrained weights)."    )# ─── Upload ──────────────────────────────────────────────────────────────────uploaded = st.file_uploader(    "Upload a chest X-ray image",    type=["jpg", "jpeg", "png"],    help="Accepts JPEG or PNG. Grayscale or RGB — the model converts to grayscale internally.",)if uploaded is None:    st.markdown("""    <div style="text-align:center;padding:3rem 0;color:#2a4a6b;font-family:'IBM Plex Mono',monospace;font-size:0.85rem">        ↑ Upload a chest X-ray to begin analysis    </div>    """, unsafe_allow_html=True)    st.stop()# ─── Run inference ────────────────────────────────────────────────────────────pil_image = Image.open(uploaded).convert("RGB")with st.spinner("Running inference…"):    t0       = time.time()    result   = run_inference(pil_image, model)    elapsed  = time.time() - t0# Apply custom threshold from sidebarlabel      = "Pneumonia" if result["prob_pneumonia"] >= threshold else "Normal"confidence = result["prob_pneumonia"] if label == "Pneumonia" else result["prob_normal"]overlay_img = make_overlay(pil_image, result["heatmap"], alpha=cam_alpha, colormap=colormap)# ─── Tabs ────────────────────────────────────────────────────────────────────tab_main, tab_detail = st.tabs(["📋  Diagnosis & Grad-CAM", "📊  Detailed Analysis"])# ══════════════════════════════════════════════════════════════════════════════# TAB 1 — Main diagnosis + Grad-CAM# ══════════════════════════════════════════════════════════════════════════════with tab_main:    col_img, col_result = st.columns([1.1, 0.9], gap="large")    with col_img:        st.markdown("**Original X-ray**")        st.image(pil_image, width="stretch", caption="Input image")        st.markdown("**Grad-CAM overlay**")        st.image(overlay_img, width="stretch",                 caption="Regions driving the prediction (warmer = more influential)")    with col_result:        # ── Prediction badge ──────────────────────────────────────────────────        badge_cls = "badge-pneumonia" if label == "Pneumonia" else "badge-normal"        icon      = "🔴" if label == "Pneumonia" else "🟢"        st.markdown(f"""        <div class="result-card">          <h3>Prediction</h3>          <span class="{badge_cls}">{icon}  {label.upper()}</span>        </div>        """, unsafe_allow_html=True)        # ── Confidence ────────────────────────────────────────────────────────        conf_pct  = confidence * 100        bar_cls   = "conf-bar-fill-pneumonia" if label == "Pneumonia" else "conf-bar-fill-normal"        st.markdown(f"""        <div class="result-card">          <h3>Confidence</h3>          <div style="font-family:'IBM Plex Mono',monospace;font-size:1.4rem;                      color:#c8d3e0;margin-bottom:0.4rem">{conf_pct:.1f}%</div>          <div class="conf-bar-container">            <div class="{bar_cls}" style="width:{conf_pct:.1f}%"></div>          </div>          <div style="display:flex;justify-content:space-between;                      font-size:0.7rem;color:#5a7fa0;margin-top:0.3rem">            <span>0%</span><span>Threshold: {threshold*100:.0f}%</span><span>100%</span>          </div>        </div>        """, unsafe_allow_html=True)        # ── Probability breakdown ─────────────────────────────────────────────        st.markdown("""<div class="result-card"><h3>Class probabilities</h3>""",                    unsafe_allow_html=True)        bar_fig = make_bar_chart(result["prob_normal"], result["prob_pneumonia"])        st.pyplot(bar_fig, use_container_width=True)        plt.close(bar_fig)        st.markdown("</div>", unsafe_allow_html=True)        # ── Quick stats ───────────────────────────────────────────────────────        m1, m2, m3 = st.columns(3)        with m1:            st.markdown(f"""            <div class="metric-tile">              <div class="value">{result['prob_pneumonia']*100:.1f}<span style="font-size:0.9rem">%</span></div>              <div class="label">P(Pneumonia)</div>            </div>""", unsafe_allow_html=True)        with m2:            st.markdown(f"""            <div class="metric-tile">              <div class="value">{result['logit']:+.2f}</div>              <div class="label">Raw logit</div>            </div>""", unsafe_allow_html=True)        with m3:            st.markdown(f"""            <div class="metric-tile">              <div class="value">{elapsed*1000:.0f}<span style="font-size:0.9rem">ms</span></div>              <div class="label">Inference</div>            </div>""", unsafe_allow_html=True)        # ── Disclaimer ────────────────────────────────────────────────────────        st.markdown("""        <div class="disclaimer">          ⚠️  <strong>For research and educational use only.</strong>          This tool is a prototype and has not been validated for clinical use.          All predictions must be reviewed and confirmed by a qualified radiologist.        </div>        """, unsafe_allow_html=True)# ══════════════════════════════════════════════════════════════════════════════# TAB 2 — Detailed analysis# ══════════════════════════════════════════════════════════════════════════════with tab_detail:    st.markdown("#### Image diagnostics")    d1, d2, d3, d4 = st.columns(4)    img_arr = np.array(pil_image.convert("L"))    with d1:        st.markdown(f"""<div class="metric-tile">          <div class="value">{pil_image.size[0]}×{pil_image.size[1]}</div>          <div class="label">Original size</div></div>""", unsafe_allow_html=True)    with d2:        st.markdown(f"""<div class="metric-tile">          <div class="value">{img_arr.mean():.1f}</div>          <div class="label">Mean intensity</div></div>""", unsafe_allow_html=True)    with d3:        st.markdown(f"""<div class="metric-tile">          <div class="value">{img_arr.std():.1f}</div>          <div class="label">Std intensity</div></div>""", unsafe_allow_html=True)    with d4:        st.markdown(f"""<div class="metric-tile">          <div class="value">{uploaded.size / 1024:.1f} KB</div>          <div class="label">File size</div></div>""", unsafe_allow_html=True)    st.markdown("---")    # ── Side-by-side: heatmap variants ────────────────────────────────────────    st.markdown("#### Grad-CAM visualizations")    vc1, vc2, vc3 = st.columns(3)    with vc1:        st.markdown("**Low opacity (0.25)**")        st.image(make_overlay(pil_image, result["heatmap"], alpha=0.25, colormap=colormap),                 width="stretch")    with vc2:        st.markdown("**Medium opacity (0.50)**")        st.image(make_overlay(pil_image, result["heatmap"], alpha=0.50, colormap=colormap),                 width="stretch")    with vc3:        st.markdown("**Heatmap only**")        hm_pil = Image.fromarray(            (plt.get_cmap(colormap)(result["heatmap"])[:, :, :3] * 255).astype(np.uint8)        )        st.image(hm_pil, width="stretch")    st.markdown("---")    # ── Activation analysis ────────────────────────────────────────────────────    st.markdown("#### Activation analysis")    ac1, ac2 = st.columns(2)    with ac1:        dist_fig = make_heatmap_distribution(result["heatmap"])        st.pyplot(dist_fig, use_container_width=True)        pl